class Solution:
    def countWinningSequences(self, s: str) -> int:
        MOD = 10**9 + 7
        delta_matrix = [
            [0, 1, -1],  # F
            [-1, 0, 1],  # W
            [1, -1, 0],  # E
        ]
        n = len(s)
        if n == 0:
            return 0
        shift = 1000
        max_diff = 1000
        # Initialize DP for the first round
        prev_dp = [[0] * (2 * shift + 1) for _ in range(3)]
        a0 = s[0]
        a0_val = 0 if a0 == 'F' else 1 if a0 == 'W' else 2
        for move in range(3):
            current_delta = delta_matrix[a0_val][move]
            shifted_diff = current_delta + shift
            prev_dp[move][shifted_diff] += 1

        # Process the remaining rounds
        for i in range(1, n):
            current_dp = [[0] * (2 * shift + 1) for _ in range(3)]
            a_i = s[i]
            a_i_val = 0 if a_i == 'F' else 1 if a_i == 'W' else 2
            for prev_last_move in range(3):
                for shifted_diff in range(2 * shift + 1):
                    count = prev_dp[prev_last_move][shifted_diff]
                    if count == 0:
                        continue
                    for curr_move in range(3):
                        if curr_move == prev_last_move:
                            continue
                        current_delta = delta_matrix[a_i_val][curr_move]
                        new_shifted_diff = shifted_diff + current_delta
                        if 0 <= new_shifted_diff <= 2 * shift:
                            current_dp[curr_move][new_shifted_diff] = (current_dp[curr_move][new_shifted_diff] + count) % MOD
            prev_dp = current_dp

        # Sum all cases where real_diff > 0
        total = 0
        for last_move in range(3):
            for shifted_diff in range(2 * shift + 1):
                real_diff = shifted_diff - shift
                if real_diff > 0:
                    total = (total + prev_dp[last_move][shifted_diff]) % MOD
        return total

