class Solution:
    def minOperations(self, nums: List[int]) -> int:
        max_num = 10**6
        spf = list(range(max_num + 1))
        for i in range(2, int(max_num**0.5) + 1):
            if spf[i] == i:  # i is a prime
                for j in range(i * i, max_num + 1, i):
                    if spf[j] == j:
                        spf[j] = i

        n = len(nums)
        if n == 0:
            return 0

        # Initialize for the first element
        if nums[0] == 1:
            prev_val1 = 1
            prev_ops1 = 0
            prev_val2 = None
            prev_ops2 = float('inf')
        else:
            prev_val1 = nums[0]
            prev_ops1 = 0
            prev_val2 = spf[nums[0]]
            prev_ops2 = 1

        for i in range(1, n):
            current_val1 = nums[i]
            current_val2 = None
            if current_val1 != 1:
                current_val2 = spf[current_val1]
            else:
                current_val2 = None

            # Compute current_ops1
            possible_ops1 = []
            if prev_val2 is not None and prev_val2 <= current_val1:
                possible_ops1.append(prev_ops2)
            if prev_val1 <= current_val1:
                possible_ops1.append(prev_ops1)
            if len(possible_ops1) == 0:
                current_ops1 = float('inf')
            else:
                current_ops1 = min(possible_ops1)

            # Compute current_ops2
            possible_ops2 = []
            if prev_val2 is not None and prev_val2 <= current_val2:
                possible_ops2.append(prev_ops2)
            if prev_val1 <= current_val2:
                possible_ops2.append(prev_ops1)
            if len(possible_ops2) == 0:
                current_ops2 = float('inf')
            else:
                current_ops2 = min(possible_ops2) + 1

            # Check if both are invalid
            if current_ops1 == float('inf') and current_ops2 == float('inf'):
                return -1

            prev_val1, prev_ops1 = current_val1, current_ops1
            prev_val2, prev_ops2 = current_val2, current_ops2

        return min(prev_ops1, prev_ops2)

