class Solution:
    def findAnswer(self, parent: List[int], s: str) -> List[bool]:
        n = len(parent)
        # Build the tree
        tree = [[] for _ in range(n)]
        for i in range(1, n):
            tree[parent[i]].append(i)

        def dfs(x):
            res = [s[x]]
            for child in tree[x]:
                res += dfs(child)
            return ''.join(res)

        answer = []
        for i in range(n):
            str_ = dfs(i)
            answer.append(str_ == str_[::-1])
        return answer

