class Solution:
    def maxScore(self, nums: List[int]) -> int:
        def compute_gcd(arr):
            if not arr:
                return 0
            current_gcd = arr[0]
            for num in arr[1:]:
                current_gcd = math.gcd(current_gcd, num)
                if current_gcd == 1:
                    break
            return current_gcd

        def compute_lcm(arr):
            if not arr:
                return 0
            current_lcm = arr[0]
            for num in arr[1:]:
                current_gcd = math.gcd(current_lcm, num)
                current_lcm = (current_lcm * num) // current_gcd
            return current_lcm

        n = len(nums)
        max_score = 0

        # Compute original array's GCD and LCM
        original_gcd = compute_gcd(nums)
        original_lcm = compute_lcm(nums)
        max_score = original_gcd * original_lcm

        # Check each possible removal
        for i in range(n):
            # Create new list without the i-th element
            new_list = nums[:i] + nums[i+1:]
            if not new_list:
                current_score = 0
            else:
                new_gcd = compute_gcd(new_list)
                new_lcm = compute_lcm(new_list)
                current_score = new_gcd * new_lcm
            if current_score > max_score:
                max_score = current_score

        return max_score

class Solution:
    def lengthAfterTransformations(self, s: str, t: int) -> int:
        MOD = 10**9 + 7
        if t == 0:
            return len(s) % MOD

        # Initialize previous array for step 0
        prev = [1] * 26

        for _ in range(t):
            curr = [0] * 26
            for c in range(26):
                if c == 25:
                    # 'z' is replaced by 'ab', so sum of 'a' and 'b' from previous step
                    curr[c] = (prev[0] + prev[1]) % MOD
                else:
                    # Replace with next character
                    curr[c] = prev[c + 1] % MOD
            prev = curr

        res = 0
        for ch in s:
            c = ord(ch) - ord('a')
            res = (res + prev[c]) % MOD

        return res

class Solution:
    def isBalanced(self, num: str) -> bool:
        sum_even = 0
        sum_odd = 0
        for i in range(len(num)):
            digit = int(num[i])
            if i % 2 == 0:
                sum_even += digit
            else:
                sum_odd += digit
        return sum_even == sum_odd

