class Solution:
    def minTimeToReach(self, moveTime: List[List[int]]) -> int:
        n = len(moveTime)
        m = len(moveTime[0])
        dist = [[float('inf')] * m for _ in range(n)]
        dist[0][0] = 0
        heap = []
        heapq.heappush(heap, (0, 0, 0))  # (arrival_time, i, j)

        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        while heap:
            curr_time, i, j = heapq.heappop(heap)
            if i == n - 1 and j == m - 1:
                return curr_time
            if curr_time > dist[i][j]:
                continue
            for dx, dy in directions:
                x = i + dx
                y = j + dy
                if 0 <= x < n and 0 <= y < m:
                    new_time = max(curr_time, moveTime[x][y]) + 1
                    if new_time < dist[x][y]:
                        dist[x][y] = new_time
                        heapq.heappush(heap, (new_time, x, y))
        return dist[n-1][m-1]

