class Solution:
    def hasIncreasingSubarrays(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        for a in range(n - 2 * k + 1):
            # Check if the subarray starting at a is strictly increasing
            is_incr1 = True
            for i in range(a, a + k - 1):
                if nums[i] >= nums[i + 1]:
                    is_incr1 = False
                    break
            # Check if the subarray starting at a + k is strictly increasing
            is_incr2 = True
            for i in range(a + k, a + 2 * k - 1):
                if nums[i] >= nums[i + 1]:
                    is_incr2 = False
                    break
            if is_incr1 and is_incr2:
                return True
        return False

class Solution:
    def countKReducibleNumbers(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        max_m = 800
        steps = [0] * (max_m + 1)
        for m in range(2, max_m + 1):
            bit_count = bin(m).count('1')
            steps[m] = 1 + steps[bit_count]

        s_digits = [int(c) for c in s]
        L = len(s_digits)
        total = 0

        for m in range(1, max_m + 1):
            if m > L:
                count_m_val = 0
            else:
                from functools import lru_cache

                def count_m():
                    @lru_cache(maxsize=None)
                    def dp(pos, cnt, tight, leading_zero):
                        if pos == L:
                            return 1 if cnt == m else 0
                        res = 0
                        max_bit = s_digits[pos] if tight else 1
                        for bit in [0, 1]:
                            if bit > max_bit:
                                continue
                            new_tight = tight and (bit == max_bit)
                            new_leading_zero = leading_zero and (bit == 0)
                            new_cnt = cnt
                            if not leading_zero:
                                new_cnt = cnt + bit
                            else:
                                if bit == 1:
                                    new_cnt = cnt + 1
                                else:
                                    new_cnt = cnt
                            res += dp(pos + 1, new_cnt, new_tight, new_leading_zero)
                        return res

                    return dp(0, 0, True, True)

                count_m_val = count_m()

            if m == 1:
                total += count_m_val
            else:
                if 1 + steps[m] <= k:
                    total += count_m_val
            total %= MOD

        return total % MOD

