class Solution:
    def countValidSelections(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0

        for curr in range(n):
            if nums[curr] != 0:
                continue
            # Try left direction (-1)
            temp = nums.copy()
            current_pos = curr
            current_dir = -1
            while True:
                if current_pos < 0 or current_pos >= n:
                    break
                if temp[current_pos] == 0:
                    current_pos += current_dir
                else:
                    temp[current_pos] -= 1
                    current_dir *= -1
                    current_pos += current_dir
            if all(x == 0 for x in temp):
                count += 1
            # Try right direction (1)
            temp = nums.copy()
            current_pos = curr
            current_dir = 1
            while True:
                if current_pos < 0 or current_pos >= n:
                    break
                if temp[current_pos] == 0:
                    current_pos += current_dir
                else:
                    temp[current_pos] -= 1
                    current_dir *= -1
                    current_pos += current_dir
            if all(x == 0 for x in temp):
                count += 1

        return count

