    def isZeroArray(self, nums: List[int], queries: List[List[int]]) -> bool:
        n = len(nums)
        delta = [0] * (n + 1)

        for l, r in queries:
            delta[l] += 1
            delta[r + 1] -= 1

        current = 0
        count = [0] * n
        for i in range(n):
            current += delta[i]
            count[i] = current

        for i in range(n):
            if count[i] < nums[i]:
                return False

        return True

class Solution:
    def minDifference(self, nums: List[int]) -> int:
        n = len(nums)
        m = nums.count(-1)
        if m == 0:
            max_diff = 0
            for i in range(n-1):
                max_diff = max(max_diff, abs(nums[i] - nums[i+1]))
            return max_diff
        elif m == 1:
            pos = nums.index(-1)
            left = nums[pos-1] if pos > 0 else float('inf')
            right = nums[pos+1] if pos < n-1 else float('inf')
            if left == float('inf') and right == float('inf'):
                return 0
            elif left == float('inf'):
                return 0
            elif right == float('inf'):
                return 0
            else:
                return (abs(right - left) + 1) // 2
        else:
            vals = [x for x in nums if x != -1]
            if len(vals) == 0:
                return 0
            elif len(vals) == 1:
                return 0
            else:
                vals.sort()
                min_diff = float('inf')
                for i in range(len(vals) - 1):
                    min_diff = min(min_diff, vals[i+1] - vals[i])
                return min_diff // 2

