class Solution:
    def minArraySum(self, nums: List[int], k: int, op1: int, op2: int) -> int:
        original_sum = sum(nums)
        # Initialize DP table with -infinity
        dp = [[-float('inf')]*(op2 + 1) for _ in range(op1 + 1)]
        dp[0][0] = 0  # Base case: 0 operations used, 0 gain

        for x in nums:
            temp_dp = [[-float('inf')]*(op2 + 1) for _ in range(op1 + 1)]
            for a in range(op1 + 1):
                for b in range(op2 + 1):
                    if dp[a][b] == -float('inf'):
                        continue
                    # Option 1: Do nothing
                    if temp_dp[a][b] < dp[a][b]:
                        temp_dp[a][b] = dp[a][b]
                    # Option 2: Apply operation 1 (divide by 2)
                    if a < op1:
                        new_a = a + 1
                        new_b = b
                        op1_gain = x - ((x + 1) // 2)
                        new_val = dp[a][b] + op1_gain
                        if temp_dp[new_a][new_b] < new_val:
                            temp_dp[new_a][new_b] = new_val
                    # Option 3: Apply operation 2 (subtract k)
                    if b < op2:
                        if x >= k:
                            op2_gain = k
                            new_a = a
                            new_b = b + 1
                            new_val = dp[a][b] + op2_gain
                            if temp_dp[new_a][new_b] < new_val:
                                temp_dp[new_a][new_b] = new_val
                    # Option 4: Apply both operations if possible
                    if a < op1 and b < op2:
                        x1 = (x + 1) // 2
                        if x1 >= k:
                            opboth_gain = (x - x1) + k
                            new_a = a + 1
                            new_b = b + 1
                            new_val = dp[a][b] + opboth_gain
                            if temp_dp[new_a][new_b] < new_val:
                                temp_dp[new_a][new_b] = new_val
            dp = temp_dp

        max_gain = 0
        for a in range(op1 + 1):
            for b in range(op2 + 1):
                if dp[a][b] > max_gain:
                    max_gain = dp[a][b]

        return original_sum - max_gain

class Solution:
    def maximizeSumOfWeights(self, edges: List[List[int]], k: int) -> int:
        # Sort edges in descending order of weight
        edges.sort(key=lambda x: -x[2])
        n = len(edges) + 1  # number of nodes is n
        degrees = [0] * n
        total = 0
        for u, v, w in edges:
            if degrees[u] < k and degrees[v] < k:
                total += w
                degrees[u] += 1
                degrees[v] += 1
        return total

