class Solution:
    def maxRemovals(self, source: str, pattern: str, targetIndices: List[int]) -> int:
        def is_valid(k):
            if k == 0:
                return self.is_subsequence(pattern, source)
            removed = set(targetIndices[-k:])
            return self.is_subsequence(pattern, source, removed)

        def is_subsequence(pattern, source, removed=None):
            if removed is None:
                removed = set()
            ptr = 0
            for i in range(len(source)):
                if i in removed:
                    continue
                if ptr < len(pattern) and source[i] == pattern[ptr]:
                    ptr += 1
            return ptr == len(pattern)

        low = 0
        high = len(targetIndices)
        ans = 0
        while low <= high:
            mid = (low + high) // 2
            if is_valid(mid):
                ans = mid
                low = mid + 1
            else:
                high = mid - 1
        return ans

    def is_subsequence(self, pattern, source):
        ptr = 0
        for c in source:
            if ptr < len(pattern) and c == pattern[ptr]:
                ptr += 1
        return ptr == len(pattern)

class Solution:
    def possibleStringCount(self, word: str) -> int:
        if not word:
            return 0
        total = 0
        current_char = word[0]
        count = 1
        for c in word[1:]:
            if c == current_char:
                count += 1
            else:
                total += (count - 1)
                current_char = c
                count = 1
        # Add the last group
        total += (count - 1)
        return total + 1

