class Solution:
    def maxScore(self, n: int, k: int, stayScore: List[List[int]], travelScore: List[List[int]]) -> int:
        # Initialize DP table
        dp = [[0] * n for _ in range(k)]

        # Fill the first day (day 0)
        for j in range(n):
            max_travel = max(travelScore[i][j] for i in range(n))
            dp[0][j] = max(stayScore[0][j], max_travel)

        # Fill the rest of the days
        for i in range(1, k):
            for j in range(n):
                # Compute max_move value for current city j
                max_move = -1
                for prev_city in range(n):
                    current_val = dp[i-1][prev_city] + travelScore[prev_city][j]
                    if current_val > max_move:
                        max_move = current_val
                # Compute option to stay
                option_stay = dp[i-1][j] + stayScore[i][j]
                dp[i][j] = max(option_stay, max_move)

        # Return the maximum value from the last day
        return max(dp[k-1])

