class Solution:
    def maxFrequency(self, nums: List[int], k: int, numOperations: int) -> int:
        nums.sort()
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        left = 0
        max_freq = 0

        for right in range(n):
            # Calculate the required sum for the current window [left, right]
            while ( (right - left + 1) * nums[right] - (prefix[right + 1] - prefix[left]) ) > numOperations * k:
                left += 1
            current_size = right - left + 1
            if current_size > max_freq:
                max_freq = current_size

        return max_freq

