    def canAliceWin(self, n: int) -> bool:
        remaining = n
        current_move = 10
        turn = 0  # 0 for Alice, 1 for Bob
        while True:
            if current_move > remaining:
                # Current player cannot make a move
                if turn == 0:
                    return False
                else:
                    return True
            elif current_move == 0:
                # Current player cannot make a move
                if turn == 0:
                    return False
                else:
                    return True
            else:
                remaining -= current_move
                current_move -= 1
                turn = 1 - turn

class Solution:
    def shiftDistance(self, s: str, t: str, nextCost: List[int], previousCost: List[int]) -> int:
        # Precompute prefix sums for nextCost and previousCost
        prefix_next = [0] * (26 + 1)
        for i in range(26):
            prefix_next[i+1] = prefix_next[i] + nextCost[i]

        prefix_previous = [0] * (26 + 1)
        for i in range(26):
            prefix_previous[i+1] = prefix_previous[i] + previousCost[i]

        total = 0

        for sc, tc in zip(s, t):
            s_char = ord(sc) - ord('a')
            t_char = ord(tc) - ord('a')
            delta = t_char - s_char

            steps_forward = delta % 26
            steps_backward = (26 - steps_forward) % 26

            # Compute cost_forward
            if steps_forward == 0:
                cost_forward = 0
            else:
                a = s_char
                b = (s_char + steps_forward - 1) % 26
                if a <= b:
                    cost_forward = prefix_next[b+1] - prefix_next[a]
                else:
                    cost_forward = (prefix_next[26] - prefix_next[a]) + (prefix_next[b+1] - prefix_next[0])

            # Compute cost_backward
            if steps_backward == 0:
                cost_backward = 0
            else:
                start = (s_char - steps_backward + 1) % 26
                end = s_char
                if start <= end:
                    cost_backward = prefix_previous[end+1] - prefix_previous[start]
                else:
                    cost_backward = (prefix_previous[26] - prefix_previous[start]) + (prefix_previous[end+1] - prefix_previous[0])

            total += min(cost_forward, cost_backward)

        return total

class Solution:
    def maxCollectedFruits(self, fruits: List[List[int]]) -> int:
        n = len(fruits)
        total = 0
        # Initialize a set to keep track of cells that have been counted
        visited = set()

        # Visit all cells on the main diagonal (i == j)
        for i in range(n):
            j = i
            if (i, j) not in visited:
                total += fruits[i][j]
                visited.add((i, j))

        # Visit all cells on the anti-diagonal (i + j == n-1)
        for i in range(n):
            j = n - 1 - i
            if (i, j) not in visited:
                total += fruits[i][j]
                visited.add((i, j))

        # Visit all cells on the bottom row (i == n-1)
        for j in range(n):
            i = n - 1
            if (i, j) not in visited:
                total += fruits[i][j]
                visited.add((i, j))

        return total

