class Solution:
    def getLargestOutlier(self, nums: List[int]) -> int:
        sum_total = sum(nums)
        freq = Counter(nums)
        candidates = []
        for o in nums:
            remaining = sum_total - o
            if remaining % 2 != 0:
                continue
            s = remaining // 2
            if s in freq:
                if o == s:
                    if freq[s] >= 2:
                        candidates.append(o)
                else:
                    candidates.append(o)
        return max(candidates)

