class Solution:
    def constructTransformedArray(self, nums: List[int]) -> List[int]:
        n = len(nums)
        result = [0] * n
        for i in range(n):
            if nums[i] == 0:
                result[i] = 0
            else:
                s = abs(nums[i])
                if nums[i] > 0:
                    new_i = (i + s) % n
                else:
                    new_i = (i - s) % n
                result[i] = nums[new_i]
        return result

class Solution:
    def maxRectangleArea(self, points: List[List[int]]) -> int:
        n = len(points)
        points_set = set((x, y) for x, y in points)
        max_area = -1

        for i in range(n):
            for j in range(i + 1, n):
                p1 = points[i]
                p2 = points[j]

                # Check if p1 and p2 are on the same vertical or horizontal line
                if p1[0] == p2[0] or p1[1] == p2[1]:
                    continue

                x1 = min(p1[0], p2[0])
                x2 = max(p1[0], p2[0])
                y1 = min(p1[1], p2[1])
                y2 = max(p1[1], p2[1])

                # Check if the other two corners exist
                if (x1, y2) in points_set and (x2, y1) in points_set:
                    # Check if there are any other points inside or on the rectangle
                    valid = True
                    corners = {(x1, y1), (x1, y2), (x2, y1), (x2, y2)}

                    for point in points:
                        pt = (point[0], point[1])
                        if pt in corners:
                            continue
                        px, py = point
                        if x1 <= px <= x2 and y1 <= py <= y2:
                            valid = False
                            break

                    if valid:
                        area = (x2 - x1) * (y2 - y1)
                        if area > max_area:
                            max_area = area

        return max_area if max_area != -1 else -1

class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        # Check if any element is less than k
        for num in nums:
            if num < k:
                return -1

        # Count the number of distinct elements greater than k
        distinct_higher = set()
        for num in nums:
            if num > k:
                distinct_higher.add(num)

        return len(distinct_higher)

import heapq

class Solution:
    def minOperations(self, n: int, m: int) -> int:
        def is_prime(x):
            if x < 2:
                return False
            if x == 2:
                return True
            if x % 2 == 0:
                return False
            for i in range(3, int(x**0.5) + 1, 2):
                if x % i == 0:
                    return False
            return True

        if is_prime(n) or is_prime(m):
            return -1

        heap = []
        heapq.heappush(heap, (n, n))
        distance = {n: n}

        while heap:
            current_cost, current_num = heapq.heappop(heap)
            if current_num == m:
                return current_cost
            current_str = str(current_num)
            length = len(current_str)
            for i in range(length):
                digit = current_str[i]
                # Try increasing the digit
                if digit < '9':
                    new_digit = str(int(digit) + 1)
                    new_str = current_str[:i] + new_digit + current_str[i+1:]
                    new_num = int(new_str)
                    if not is_prime(new_num):
                        if new_num not in distance or current_cost + new_num < distance.get(new_num, float('inf')):
                            distance[new_num] = current_cost + new_num
                            heapq.heappush(heap, (distance[new_num], new_num))
                # Try decreasing the digit
                if digit > '0':
                    new_digit = str(int(digit) - 1)
                    new_str = current_str[:i] + new_digit + current_str[i+1:]
                    new_num = int(new_str)
                    if not is_prime(new_num):
                        if new_num not in distance or current_cost + new_num < distance.get(new_num, float('inf')):
                            distance[new_num] = current_cost + new_num
                            heapq.heappush(heap, (distance[new_num], new_num))
        return -1

