class DSU:
    def __init__(self, elements):
        self.parent = {}
        self.rank = {}
        for x in elements:
            self.parent[x] = x
            self.rank[x] = 1

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1

    def get_components_count(self):
        roots = set()
        for x in self.parent:
            roots.add(self.find(x))
        return len(roots)

class Solution:
    def countComponents(self, nums: List[int], threshold: int) -> int:
        # Step 1: filter numbers <= threshold
        filtered = [x for x in nums if x <= threshold]
        isolated_count = len(nums) - len(filtered)
        nums_set = set(nums)

        if not filtered:
            return isolated_count

        # Step 2: Initialize DSU
        dsu = DSU(filtered)

        # Step 3: For each m from 1 to threshold, find factors and process
        for m in range(1, threshold + 1):
            # Find all factors of m
            factors = set()
            for i in range(1, int(math.isqrt(m)) + 1):
                if m % i == 0:
                    factors.add(i)
                    factors.add(m // i)
            # collect factors that are in nums_set
            candidates = [f for f in factors if f in nums_set]
            if len(candidates) >= 2:
                # connect all candidates
                first = candidates[0]
                for f in candidates[1:]:
                    dsu.union(first, f)

        # Step 4: count components in DSU
        components = dsu.get_components_count()
        return isolated_count + components

