class Solution:
    def buttonWithLongestTime(self, events: List[List[int]]) -> int:
        if not events:
            return -1  # According to constraints, events is not empty
        prev_time = events[0][1]
        max_time = prev_time
        result_button = events[0][0]
        for i in range(1, len(events)):
            current_time = events[i][1]
            time_taken = current_time - prev_time
            if time_taken > max_time:
                max_time = time_taken
                result_button = events[i][0]
            elif time_taken == max_time:
                if events[i][0] < result_button:
                    result_button = events[i][0]
            prev_time = current_time
        return result_button

