class Solution:
    def maxAmount(self, initialCurrency: str, pairs1: List[List[str]], rates1: List[float], pairs2: List[List[str]], rates2: List[float]) -> float:
        # Process day1
        # Collect all currencies in day1
        currencies_day1 = set()
        for pair in pairs1:
            currencies_day1.add(pair[0])
            currencies_day1.add(pair[1])
        currencies_day1.add(initialCurrency)

        # Build edges for day1
        edges_day1 = []
        for i in range(len(pairs1)):
            start, target = pairs1[i]
            rate = rates1[i]
            edges_day1.append( (start, target, rate) )
            edges_day1.append( (target, start, 1.0 / rate) )

        # Compute max_amount for day1
        initial_values_day1 = {currency: 0.0 for currency in currencies_day1}
        initial_values_day1[initialCurrency] = 1.0

        V = len(currencies_day1)
        for _ in range(V-1):
            updated = False
            for (u, v, rate) in edges_day1:
                if initial_values_day1[u] * rate > initial_values_day1[v]:
                    initial_values_day1[v] = initial_values_day1[u] * rate
                    updated = True
            if not updated:
                break

        max_day1 = initial_values_day1

        # Process day2
        # Collect all currencies in day2
        currencies_day2 = set()
        for pair in pairs2:
            currencies_day2.add(pair[0])
            currencies_day2.add(pair[1])

        # Build edges for day2
        edges_day2 = []
        for i in range(len(pairs2)):
            start, target = pairs2[i]
            rate = rates2[i]
            edges_day2.append( (start, target, rate) )
            edges_day2.append( (target, start, 1.0 / rate) )

        # initial_values_day2 is the values from max_day1 for currencies_day2
        initial_values_day2 = {currency: max_day1.get(currency, 0.0) for currency in currencies_day2}

        V2 = len(currencies_day2)
        for _ in range(V2-1):
            updated = False
            for (u, v, rate) in edges_day2:
                if initial_values_day2[u] * rate > initial_values_day2[v]:
                    initial_values_day2[v] = initial_values_day2[u] * rate
                    updated = True
            if not updated:
                break

        # Return the answer
        return initial_values_day2.get(initialCurrency, max_day1[initialCurrency])

