class Solution:
    def maxDistinctElements(self, nums: List[int], k: int) -> int:
        nums.sort()
        prev = -float('inf')
        count = 0
        for num in nums:
            if prev == -float('inf'):
                # First element, adjust to the minimum possible value
                adjusted = num - k
                count += 1
                prev = adjusted
            else:
                desired = prev + 1
                if desired <= num + k:
                    count += 1
                    prev = desired
        return count

class Solution:
    def minLength(self, s: str, numOps: int) -> int:
        # Split the string into runs of consecutive characters
        runs = []
        n = len(s)
        if n == 0:
            return 0
        current = s[0]
        count = 1
        for i in range(1, n):
            if s[i] == current:
                count += 1
            else:
                runs.append(count)
                current = s[i]
                count = 1
        runs.append(count)

        # Binary search to find the minimum possible maximum length
        left = 1
        right = n
        answer = n  # Initialize with the maximum possible length

        while left <= right:
            mid = (left + right) // 2
            required = 0
            for run in runs:
                if run > mid:
                    # Calculate the number of operations needed for this run
                    ops = (run + mid) // (mid + 1) - 1
                    required += ops
            if required <= numOps:
                answer = mid
                right = mid - 1
            else:
                left = mid + 1

        return answer

class Solution:
    def answerString(self, word: str, numFriends: int) -> str:
        n = len(word)
        L = n - (numFriends - 1)
        max_str = ''
        for i in range(n):
            max_len = min(L, n - i)
            current_sub = word[i:i+max_len]
            if current_sub > max_str:
                max_str = current_sub
        return max_str

