class Solution:
    def numberOfSubsequences(self, nums: List[int]) -> int:
        n = len(nums)
        max_num = 1000
        # Precompute suffix counts
        suffix = [[0] * (max_num + 1) for _ in range(n)]
        for i in range(n-1, -1, -1):
            if i == n-1:
                suffix[i][nums[i]] = 1
            else:
                for x in range(max_num + 1):
                    suffix[i][x] = suffix[i+1][x]
                suffix[i][nums[i]] += 1
        total = 0
        # Iterate over all possible q and r
        for q in range(2, n-2):
            for r in range(q + 2, n - 2):
                target = nums[q]
                # Iterate over possible p in the allowed range
                for p in range(0, q - 1):
                    if q - p < 2:
                        continue
                    # Calculate the required product for s
                    product_pr = nums[p] * nums[r]
                    if product_pr % target != 0:
                        continue
                    required_s = product_pr // target
                    s_start = r + 2
                    if s_start >= n:
                        continue
                    total += suffix[s_start][required_s]
        return total

