class Solution:
    def countPathsWithXorValue(self, grid: List[List[int]], k: int) -> int:
        m = len(grid)
        n = len(grid[0])
        MOD = 10**9 + 7

        # Initialize a 3D DP array: dp[i][j][x] represents the number of ways to reach (i,j) with XOR value x
        dp = [[[0] * 16 for _ in range(n)] for _ in range(m)]

        # Starting cell (0,0)
        dp[0][0][grid[0][0]] = 1

        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                current_val = grid[i][j]
                temp = [0] * 16
                # Check the cell above (i-1, j)
                if i > 0:
                    for x in range(16):
                        new_x = x ^ current_val
                        temp[new_x] = (temp[new_x] + dp[i-1][j][x]) % MOD
                # Check the cell to the left (i, j-1)
                if j > 0:
                    for x in range(16):
                        new_x = x ^ current_val
                        temp[new_x] = (temp[new_x] + dp[i][j-1][x]) % MOD
                dp[i][j] = temp

        return dp[m-1][n-1][k] % MOD

