class Solution:
    def maxLength(self, nums: List[int]) -> int:
        n = len(nums)
        max_len = 1  # Minimum possible length is 1
        for i in range(n):
            current_gcd = nums[i]
            current_lcm = nums[i]
            product = nums[i]
            for j in range(i, n):
                if j == i:
                    pass
                else:
                    current_gcd = math.gcd(current_gcd, nums[j])
                    current_lcm = (current_lcm * nums[j]) // math.gcd(current_lcm, nums[j])
                    product *= nums[j]
                if product == current_lcm * current_gcd:
                    current_len = j - i + 1
                    if current_len > max_len:
                        max_len = current_len
        return max_len

