class Solution:
    def calculateScore(self, s: str) -> int:
        stacks = defaultdict(list)
        score = 0
        for i, c in enumerate(s):
            # Compute the mirror character
            mirror_char = chr(ord('a') + 25 - (ord(c) - ord('a')))
            if stacks[mirror_char]:
                j = stacks[mirror_char].pop()
                score += i - j
            stacks[c].append(i)
        return score

import bisect

class Solution:
    def maximumWeight(self, intervals: List[List[int]]) -> List[int]:
        def is_lex_smaller(a, b):
            min_len = min(len(a), len(b))
            for i in range(min_len):
                if a[i] < b[i]:
                    return True
                elif a[i] > b[i]:
                    return False
            return len(a) < len(b)

        # Sort intervals by end time, then start time, then original index
        sorted_intervals = []
        for idx, (l, r, w) in enumerate(intervals):
            sorted_intervals.append((r, l, w, idx))
        sorted_intervals.sort(key=lambda x: (x[0], x[1], x[3]))

        # Extract end times for binary search
        ends = [x[0] for x in sorted_intervals]
        n = len(sorted_intervals)

        # Initialize dp array: dp[k] is (max_weight, list_of_indices)
        dp = [None] * 5  # indices 0 to 4, 0 unused

        for i in range(n):
            current_r, current_l, current_w, original_idx = sorted_intervals[i]

            for k in range(1, 5):
                if k == 1:
                    candidate_weight = current_w
                    candidate_indices = [original_idx]
                    if dp[k] is None:
                        dp[k] = (candidate_weight, candidate_indices)
                    else:
                        existing_weight, existing_indices = dp[k]
                        if candidate_weight > existing_weight:
                            dp[k] = (candidate_weight, candidate_indices)
                        elif candidate_weight == existing_weight:
                            if is_lex_smaller(candidate_indices, existing_indices):
                                dp[k] = (candidate_weight, candidate_indices)
                else:
                    # k >= 2
                    idx = bisect.bisect_right(ends, current_l) - 1
                    if idx >= 0:
                        if dp[k-1] is not None:
                            prev_weight, prev_indices = dp[k-1]
                            new_weight = prev_weight + current_w
                            new_indices = prev_indices + [original_idx]
                            if dp[k] is None:
                                dp[k] = (new_weight, new_indices)
                            else:
                                existing_weight, existing_indices = dp[k]
                                if new_weight > existing_weight:
                                    dp[k] = (new_weight, new_indices)
                                elif new_weight == existing_weight:
                                    if is_lex_smaller(new_indices, existing_indices):
                                        dp[k] = (new_weight, new_indices)

        # Find the best selection among dp[1], dp[2], dp[3], dp[4]
        max_score = -1
        best_selection = []
        for k in range(1, 5):
            if dp[k] is not None:
                weight, indices = dp[k]
                if weight > max_score:
                    max_score = weight
                    best_selection = indices
                elif weight == max_score:
                    if is_lex_smaller(indices, best_selection):
                        best_selection = indices

        return best_selection

class Solution:
    def hasMatch(self, s: str, p: str) -> bool:
        star_idx = p.index('*')
        prefix = p[:star_idx]
        suffix = p[star_idx+1:]
        n = len(s)
        for i in range(n):
            for j in range(i, n):
                substr = s[i:j+1]
                len_sub = j - i + 1
                if len_sub < len(prefix) + len(suffix):
                    continue
                if substr.startswith(prefix) and substr.endswith(suffix):
                    return True
        return False

