class Solution:
    def longestSubsequence(self, nums: List[int]) -> int:
        n = len(nums)
        max_diff = 300  # Since nums[i] can be up to 300, the max difference is 299
        dp = [[1] * max_diff for _ in range(n)]
        max_suffix = [[0] * max_diff for _ in range(n)]

        for i in range(n):
            for j in range(i):
                d = abs(nums[i] - nums[j])
                if d < max_diff:
                    max_prev = max_suffix[j][d]
                    if dp[i][d] < max_prev + 1:
                        dp[i][d] = max_prev + 1
            # Compute max_suffix for current i
            for d in range(max_diff - 1, -1, -1):
                if d == max_diff - 1:
                    max_suffix[i][d] = dp[i][d]
                else:
                    max_suffix[i][d] = max(dp[i][d], max_suffix[i][d + 1])

        max_len = 0
        for i in range(n):
            current_max = max(dp[i])
            if current_max > max_len:
                max_len = current_max
        return max_len

