import collections

def main():
    N, M = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))
    # Convert A to 0-based index
    A = [a-1 for a in A]

    # Build graph
    graph = [[] for _ in range(N)]
    for i in range(N):
        graph[i].append(A[i])

    # Step 1: Find SCCs using Kosaraju's algorithm
    visited = [False] * N
    order = []

    def dfs1(u):
        stack = [(u, False)]
        while stack:
            node, processed = stack.pop()
            if processed:
                order.append(node)
                continue
            if visited[node]:
                continue
            visited[node] = True
            stack.append((node, True))
            for v in graph[node]:
                if not visited[v]:
                    stack.append((v, False))

    for i in range(N):
        if not visited[i]:
            dfs1(i)

    # Build reverse graph
    reverse_graph = [[] for _ in range(N)]
    for u in range(N):
        for v in graph[u]:
            reverse_graph[v].append(u)

    visited = [False] * N
    scc = []

    def dfs2(u, component):
        stack = [u]
        visited[u] = True
        component.append(u)
        while stack:
            node = stack.pop()
            for v in reverse_graph[node]:
                if not visited[v]:
                    visited[v] = True
                    component.append(v)
                    stack.append(v)

    for i in reversed(order):
        if not visited[i]:
            component = []
            dfs2(i, component)
            scc.append(component)

    # Step 2: Build DAG of SCCs and topological sort
    scc_id = [0]*N
    for i in range(len(scc)):
        for node in scc[i]:
            scc_id[node] = i

    # Build edges between SCCs
    dag_edges = collections.defaultdict(set)
    for u in range(N):
        for v in graph[u]:
            if scc_id[u] != scc_id[v]:
                dag_edges[scc_id[u]].add(scc_id[v])

    # Topological sort on the DAG
    in_degree = [0]*len(scc)
    for u in range(len(scc)):
        for v in dag_edges[u]:
            in_degree[v] += 1

    q = collections.deque()
    for i in range(len(scc)):
        if in_degree[i] == 0:
            q.append(i)

    top_order = []
    while q:
        u = q.popleft()
        top_order.append(u)
        for v in dag_edges[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Step 3: Dynamic programming
    dp = [0] * (M + 2)  # dp[0] unused
    for k in range(1, M + 1):
        dp[k] = 1

    for component in top_order:
        # Compute prefix sums
        new_dp = [0] * (M + 2)
        for k in range(1, M + 1):
            new_dp[k] = new_dp[k-1] + dp[k]
        dp = new_dp

    result = sum(dp[1:M+1]) % 998244353
    print(result)

