import sys

def count_upto(n, max_digit):
    if n < 0:
        return 0
    s = str(n)
    digits = list(map(int, s))
    from functools import lru_cache

    @lru_cache(maxsize=None)
    def dp(pos, tight, leading_zero):
        if pos == len(digits):
            return 1
        res = 0
        upper = digits[pos] if tight else 9
        for d in range(0, upper + 1):
            if d > max_digit:
                continue
            new_tight = tight and (d == upper)
            new_leading_zero = leading_zero and (d == 0)
            res += dp(pos + 1, new_tight, new_leading_zero)
        return res

    return dp(0, True, True)

