def main():
    sys.setrecursionlimit(1 << 25)
    N = int(sys.stdin.readline())
    A = list(map(int, sys.stdin.readline().split()))

    # Precompute the sum for each possible mask
    pre_sum = [0] * (1 << N)
    for mask in range(1 << N):
        s = 0
        for i in range(N):
            if mask & (1 << i):
                s += A[i]
        pre_sum[mask] = s

    memo = {}

    def dp(mask):
        if mask in memo:
            return memo[mask]
        if mask == 0:
            memo[mask] = {0}
            return memo[mask]
        res = set()
        s = mask
        while s:
            sum_s = pre_sum[s]
            remaining_mask = mask ^ s
            for val in dp(remaining_mask):
                res.add(sum_s ^ val)
            s = (s - 1) & mask
        memo[mask] = res
        return res

    answer = len(dp((1 << N) - 1))
    print(answer)

